	public function new_chat_window(Request $request) {

        $user_id = Auth::user()->id;
        $data['userinfo'] =  DB::table('users')
							->leftJoin('member_school', 'member_school.user_id', '=', 'users.id')
							->leftJoin('member_section', 'member_section.user_id', '=', 'users.id')
							->select('users.id','users.fullname as name','users.profile_pic','member_school.school_id','member_section.grade_id','member_section.section_id')
							->where(['users.role_id'=>3,'users.id'=>$user_id])
							->first();
		$data['user_id'] =  $user_id;
	    return view('/student/chat_window')->with($data);
    }
    	
	public function getLoadTeacherList(Request $request){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
        $userinfo = DB::table('users')
					->where([
						['users.institute_id', '=', $institute_id],
						['users.id', '=', $user_id],
						['users.role_id', '=', 3],
						['users.status', '=', 1],
					])
					->select('users.id','users.fullname', 'member_school.school_id', 'member_section.grade_id', 'member_section.section_id')
					->Join('member_school', function ($join) use ($academic_session_id, $semester_id) {
						$join->on('member_school.user_id', '=', 'users.id')
						->where('member_school.academic_session_id', $academic_session_id)
						->where('member_school.semester_id', $semester_id)
						->where('member_school.status', 1);
					})
					->Join('member_section', function ($join) use ($academic_session_id, $semester_id) {
						$join->on('member_section.user_id', '=', 'users.id')
						->where('member_section.academic_session_id', $academic_session_id)
						->where('member_section.semester_id', $semester_id)
						->where('member_section.status', 1);
					})
					//->Join('member_school', 'member_school.user_id', '=', 'users.id')
					//->Join('member_section', 'member_section.user_id', '=', 'users.id')
					->first();
					
					$myteacher = DB::table('users')
								->select('users.id', 'users.fullname as name', 'users.profile_pic', 'users.is_login', 'grades.school_id','member_section.grade_id','grades.grade as grade_name','member_section.section_id','section_name')
								->join('member_section', function ($join) use ($userinfo,$academic_session_id,$semester_id){
									$join->on('member_section.user_id', '=', 'users.id')
										->where('member_section.status', '=', 1)
										->where('member_section.academic_session_id', $academic_session_id)
										->where('member_section.semester_id', $semester_id)
										->where('member_section.section_id', '=', $userinfo->section_id);
								})
								->join('member_grade', function ($join) use ($userinfo,$academic_session_id,$semester_id) {
									$join->on('member_grade.user_id', '=', 'users.id')
										->where('member_grade.academic_session_id', $academic_session_id)
										->where('member_grade.semester_id', $semester_id)
										->where('member_grade.status', '=', 1)
										->where('member_grade.grade_id', '=', $userinfo->grade_id);
								})
								->join('grades', function ($join) use ($userinfo) {
									$join->on('grades.id', '=', 'member_grade.grade_id')
										->where('grades.school_id', '=', $userinfo->school_id);
								})
								->where('users.role_id', '=',2)
								->where('users.institute_id', '=', $institute_id)
								->orderBy('users.first_name', 'ASC')
								->get()
								->all(); 
									
		$mainGroupArr =array(); 
		$groupsArr = array();
		$singleArr = array();
					
		if(!empty($myteacher)){
			foreach($myteacher as $key=>$myteacherVal){
				
				$main_group_id = base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$myteacherVal->id);
				$main_group_name = $myteacherVal->grade_name.'-'.$myteacherVal->section_name.'-('.ucfirst($myteacherVal->name).')';
				
				$groupsArr[] = array('institute_id'=>$institute_id,
									 'group_id'=>$main_group_id,	
									 'group_name'=>$main_group_name,
									 'group_image'=>url('/').'/public/uploads/icon/icon_1644316802.png',										 
									 'chat_type'=>2,	
									 'status'=>1,	
									 'created_at' => date('Y-m-d H:i:s'),
									);
									
				$mainGroupArr[$key] = new \stdClass(); //the magic see new object member created on the fly without warning.
				$mainGroupArr[$key]->id = $myteacherVal->id;
				$mainGroupArr[$key]->main_group_id = $main_group_id;
				$mainGroupArr[$key]->name = $myteacherVal->name;
				$mainGroupArr[$key]->group_name = $main_group_name;
				$mainGroupArr[$key]->group_image = url('/').'/public/uploads/icon/icon_1644316802.png';
				$mainGroupArr[$key]->school_id = $myteacherVal->memberSchool->school_id;	
				$mainGroupArr[$key]->grade_id =  $myteacherVal->memberGrade->grade_id;
				$mainGroupArr[$key]->section_id = $myteacherVal->memberSection->section_id;	
				
				$groupID =  base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$user_id.'-'.$myteacherVal->id);
				
				$groupsArr[] = array('institute_id'=>$institute_id,
									 'group_id'=>$groupID,	
									 'group_name'=>ucfirst($myteacherVal->name).'-'.ucfirst($userinfo->fullname),
									 'group_image'=>!empty($myteacherVal->profile_pic)? $myteacherVal->profile_pic: '',										 
									 'chat_type'=>1,	
									 'status'=>1,	
									 'created_at' => date('Y-m-d H:i:s'),
									);
				
				$last_msg_info = DB::table('chat_msg as c')
					->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%h:%i %p') as time"),'c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
					->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
					->where('c.group_id', '=', $groupID)
					->where('c.institute_id', $institute_id)
					->where('c.academic_session_id', $academic_session_id)
					->where('c.semester_id', $semester_id)
					->orderBy('c.id', 'DESC')
					->first();
				$myteacher[$key]->main_group_id = '';	
				$myteacher[$key]->school_id = $myteacherVal->school_id;	
				$myteacher[$key]->grade_id =  $myteacherVal->grade_id;
				$myteacher[$key]->section_id = $myteacherVal->section_id;	
				$myteacher[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
				$myteacher[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
				$myteacher[$key]->time = !empty($last_msg_info->time) ? Helper::getTime($last_msg_info->time) : '';	
				$myteacher[$key]->group_id = $groupID;	
				$myteacher[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
				$myteacher[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
				$myteacher[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
				$myteacher[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
				$myteacher[$key]->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';	
				//$myteacher[$key]->total_message = Helper::getGroupMessageCount($user_id,$groupID);
			}
		}
		
		if(!empty($mainGroupArr)){
			foreach($mainGroupArr as $key=>$mainGroupArrval){
				$main_group_id = !empty($mainGroupArrval->main_group_id)? $mainGroupArrval->main_group_id :'';
				$tutor_id = $mainGroupArrval->id;
				$last_msg_info = DB::table('chat_msg as c')
				->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%h:%i %p') as time"),'c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
				->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
				->where('c.group_id', '=', $main_group_id)
				->where('c.institute_id', $institute_id)
				->where('c.academic_session_id', $academic_session_id)
				->where('c.semester_id', $semester_id)
				->orderBy('c.id', 'DESC')
				->first();
				$mainGroupArr[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
				$mainGroupArr[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
				$mainGroupArr[$key]->time = !empty($last_msg_info->time) ? Helper::getTime($last_msg_info->time) : '';	
				$mainGroupArr[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
				$mainGroupArr[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
				$mainGroupArr[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
				$mainGroupArr[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
				$mainGroupArr[$key]->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';	
				array_push($myteacher,$mainGroupArrval);
			}
		}
		
		if(!empty($groupsArr)){
			DB::table('chat_group')->insertOrIgnore($groupsArr);
		}
		
		$teacherData = collect($myteacher)->sortByDesc('chat_id')->values();
	    $data['user_id'] =  $user_id;
	    $data['userinfo'] =  $userinfo;
	    $data['myteacher'] =  $teacherData;
	    $returnHTML = view('student/_teacher_list_chat')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
		
