	public function getTeacherSharedMaterial(Request $request){
		$user_id = Auth::user()->id;
        $userinfo = DB::table('users')
							 ->Join('member_section', 'member_section.user_id', '=', 'users.id')
							 ->Join('member_school', 'member_school.user_id', '=', 'users.id')
							->select('users.id','member_school.school_id','member_section.grade_id','member_section.section_id')
							->where('users.id', '=', $user_id)
							->where('users.role_id', '=', 3)
							->where('users.status', '=', 1)
							->first();
		$myteacher = DB::table('users')
			->select('users.id', 'users.fullname as name','users.profile_pic','users.is_login','member_school.school_id','member_grade.grade_id','member_grade.grade_name','member_section.section_id','member_section.section_name')
			->Join('member_school', 'member_school.user_id', '=', 'users.id')
			->join('member_grade', 'member_grade.user_id', '=', 'users.id')
			->Join('member_section', 'member_section.user_id', '=', 'users.id')
			->where('member_school.school_id', '=', $userinfo->school_id)
			->Where('member_grade.grade_id', '=', $userinfo->grade_id)
			->Where('member_section.section_id', '=', $userinfo->section_id)
			->where('users.role_id', '=', 2)
			->where('users.status', '=', 1)
			->groupBy('users.id')
			->orderBy('users.first_name', 'asc')
			->get()
			->all();
		$data['myteacher'] =  $myteacher;
	    $returnHTML = view('student/_teacher_shared_material')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
		
	public function submit_chat(Request $request) {
			
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$recevier_id = $request->input('recevier_id');
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		
		$msg_time = $request->input('msg_time');
		$active_group_id = $request->input('active_group_id');

		$message = trim($request->input('message'));
