	public function shareFileImage(Request $request) {
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		$active_group_id = $request->input('active_group_id');
	
		$message = trim($request->input('txt_message'));
		$recevier_id = $request->input('recevier_id');
		
		$date_time = $request->input('date_time');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('d-M-Y h:i a',trim($date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
	    $student_group =  DB::table('member_section')
						  ->join('member_school','member_school.user_id','=','member_section.user_id')
						  ->select('member_school.school_id','section_id','grade_id')->where('member_section.user_id', '=', $user_id)->where('member_section.status',1)->first();
	
		$section_grade = !empty($student_group) ? $student_group->section_id.'_'.$student_group->grade_id : '';
		$parent_group = !empty($student_group) ? base64_encode($student_group->school_id.''.$student_group->grade_id.''.$student_group->section_id): '';
		$message_txt  =  "'".$message."'";
		$singleImgCls = "";
		$imgArr = array();
		if ($request->hasfile('file')) {
			foreach($request->file('file') as $file) {
				$extension = $file->getClientOriginalExtension();
				$file_mime_type = $file->getClientMimeType();
				$upload_path = public_path().'/uploads/chat_share_file/';
				if (!file_exists($upload_path)) {
					mkdir($upload_path, 0777, true);
				}
				$file_name = uniqid().'_'.time().'.'.$extension;
				$file->move($upload_path, $file_name);
				$imgArr[] = array('file_name'=>$file_name,
									'file_mime_type'=>$file_mime_type,
									'file_type'=>1,
									'created_date'=>$utcCurrentDateTime);
			}
		}
		$senderArr = array(
					'sender_id' => $user_id ,
					'institute_id' => $institute_id,
					'academic_session_id' => $academic_session_id,
					'semester_id' => $semester_id,
					'msg' => $message,
					'is_share_file' => 1,
					'file_type' =>1,
					'status' => 1,
					'created_at' => $utcCurrentDateTime,
				);
		$groupMember ="";
		$chatMsgStatus= array();
		if(!empty($gradesection_group_id) && empty($group_id) && empty($groupchat_id) && empty($b2c_group_id)){
			$groupMember = 	Helper::getGradeSectionGroupMember($user_id,$recevier_id,$student_group,$institute_id);
			$senderArr['group_id'] = $gradesection_group_id;
			$senderArr['is_name_header'] = 1;
			$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
			if($insert_Id){
				foreach($groupMember as $key=>$recevierIdArrVal){
					$chatMsgStatus[] = array(
						'receiver_id' => $recevierIdArrVal,
						'chat_msg_id' =>$insert_Id,
						'is_read' => 0,
						'status' => 0,
						'chat_msg_type' => 1,
