	public function studentReplayChatRecordingUpload(Request $request){
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		$recevier_id = $request->input('recevier_id');
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		
		
		$date_time = $request->input('date_time');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',trim($currentDateTime), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
	
		
		$active_group_id = $request->input('active_group_id');
		$reply_message_id = $request->input('reply_message_id');
		$reply_share_message_id = $request->input('reply_share_message_id');
		
		$track_duration = $request->input('track_duration');
		$recording_duration = $request->input('recording_duration');
		
		$student_group =  DB::table('member_section')
					  ->join('member_school','member_school.user_id','=','member_section.user_id')
					  ->select('member_school.school_id','section_id','grade_id')->where('member_section.user_id', '=', $user_id)->where('member_section.status',1)->first();
	
		$section_grade = !empty($student_group) ? $student_group->section_id.'_'.$student_group->grade_id : '';
