										'chat_id'=>$chat_id,
										'section_grade'=>$section_grade,
										'message_type'=>''
										);                              	
				}
			event(new ChatMessage($msgsend));
			return response()->json(['status' => true,'message'=>'recording upload successfully','id' => $insert_Id,'share_file' =>$share_file,'message_type'=>$message_type]);
		}
		else{
		  return response()->json(['status' => false,'message'=>'internal error please try again']);
		}
	}
	
	public function serachTxt(Request $request) {
		
        $user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
	    $user_serach_txt = $request->user_serach_txt;
		$current_active_group = $request->current_active_group;
        $grouptype = $request->grouptype;
		$returnHTML="";
		
		if($grouptype=='groups'){
		
			$chatGroup = DB::table('chat_group')
						->join('chat_group_member', function ($join) use($user_id) {
							$join->on('chat_group_member.group_id', '=', 'chat_group.id')
								->where('chat_group_member.user_id', '=', $user_id);
						})
						->select('chat_group.id', 'chat_group.group_name', 'chat_group.group_image', 'chat_group.group_id', DB::raw('(SELECT COUNT(*) FROM chat_msg JOIN chat_msg_status ON chat_msg_status.chat_msg_id = chat_msg.id WHERE chat_msg.group_id = chat_group.group_id AND chat_msg_status.receiver_id = "' . $user_id . '" AND chat_msg_status.is_read = 0 AND chat_msg_status.status = 0) AS unread_count'))
						->where(['chat_group.institute_id'=>$institute_id, 'chat_group.status'=>1])
						->where(function ($query) use ($user_serach_txt) {
							$query->orWhere('group_name', 'like', '%' . $user_serach_txt . '%');
						})
						->get()
						->all();
					if (!empty($chatGroup)) {
						foreach ($chatGroup as $key => $chat_groupVal) {
							$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file', 'c.is_link', 'chat_shared_file.file_type', 'chat_shared_file.file_name', 'chat_shared_file.file_mime_type', 'chat_shared_file.is_recording')
								->leftJoin('chat_shared_file', 'chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $chat_groupVal->group_id)
								->orderBy('created_at', 'DESC')
								->first();
							$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';
							$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';
							$chatGroup[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
							$chatGroup[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';
							$chatGroup[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';
							$chatGroup[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';
							$chatGroup[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
							$chatGroup[$key]->unread_count = $chat_groupVal->unread_count;
						}
					}
				$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();						
				$data['student_id'] = $user_id;
				$data['chat_group'] = $chat_group;
				$returnHTML = view('student/_chat_group_list')->with($data)->render();
		}
		elseif($grouptype=='b2c'){
			$data['user_id'] = $user_id;
			$data['userTimeZone'] = $userTimeZone; 
			$data['active_group_id'] = $request->active_group_id;
			$data['groups'] = DB::table('chat_group')
							->select('users.id','users.fullname', 'users.profile_pic','users.is_login','chat_group.group_id','last_msg.msg','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','last_msg.created_at')
							->join('users', 'chat_group.tutor_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->whereRaw('last_msg.id = (SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)');
							})
							 ->leftJoin('chat_shared_file', function ($join) {
								$join->on('chat_shared_file.chat_id', '=', 'last_msg.id')
									->whereExists(function ($query) {
										$query->select(DB::raw(1))
											->from('chat_shared_file')
											->whereRaw('chat_shared_file.chat_id = last_msg.id')
											->orderByDesc('chat_shared_file.id')
											->limit(1);
									});
							})
							->where('chat_group.student_id', $user_id)
							->where(function ($query) use ($user_serach_txt) {
									$query->orWhere('users.fullname', 'like', '%' . $user_serach_txt . '%');
							})
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();
			$returnHTML = view('student/_b2c_user_list')->with($data)->render();
		}
		else{
		
		 $userinfo = DB::table('users')
					->where([
						['users.institute_id', '=', $institute_id],
						['users.id', '=', $user_id],
						['users.role_id', '=', 3],
						['users.status', '=', 1],
					])
					->select('users.id','users.fullname', 'member_school.school_id', 'member_section.grade_id', 'member_section.section_id')
					->Join('member_school', function ($join) use ($academic_session_id, $semester_id) {
						$join->on('member_school.user_id', '=', 'users.id')
						->where('member_school.academic_session_id', $academic_session_id)
						->where('member_school.semester_id', $semester_id)
						->where('member_school.status', 1);
					})
					->Join('member_section', function ($join) use ($academic_session_id, $semester_id) {
						$join->on('member_section.user_id', '=', 'users.id')
						->where('member_section.academic_session_id', $academic_session_id)
						->where('member_section.semester_id', $semester_id)
						->where('member_section.status', 1);
					})
					->first();
			$myteacher = DB::table('users')
						->select('users.id', 'users.fullname as name', 'users.profile_pic', 'users.is_login', 'grades.school_id','member_section.grade_id','grades.grade as grade_name','member_section.section_id','section_name')
						->join('member_section', function ($join) use ($userinfo,$academic_session_id,$semester_id){
							$join->on('member_section.user_id', '=', 'users.id')
								->where('member_section.status', '=', 1)
								->where('member_section.academic_session_id', $academic_session_id)
								->where('member_section.semester_id', $semester_id)
								->where('member_section.section_id', '=', $userinfo->section_id);
						})
						->join('member_grade', function ($join) use ($userinfo,$academic_session_id,$semester_id) {
							$join->on('member_grade.user_id', '=', 'users.id')
								->where('member_grade.academic_session_id', $academic_session_id)
								->where('member_grade.semester_id', $semester_id)
								->where('member_grade.status', '=', 1)
								->where('member_grade.grade_id', '=', $userinfo->grade_id);
						})
						->join('grades', function ($join) use ($userinfo) {
							$join->on('grades.id', '=', 'member_grade.grade_id')
								->where('grades.school_id', '=', $userinfo->school_id);
						})
						->where('users.role_id', '=',2)
						->where('users.institute_id', '=', $institute_id)
						->where(function ($query) use ($user_serach_txt) {
							$query->orWhere('users.fullname', 'like', '%' . $user_serach_txt . '%');
							$query->orWhere('grade_name', 'like', '%' . $user_serach_txt . '%');
							$query->orWhere('section_name', 'like', '%' . $user_serach_txt . '%');
						})
						->groupBy('users.id')
						->orderBy('users.first_name', 'ASC')
						->get()
						->all(); 
						
				$mainGroupArr =array(); 
								
				if(!empty($myteacher)){
					foreach($myteacher as $key=>$myteacherVal){
						
						$main_group_id = base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$myteacherVal->id);
						$main_group_name = $myteacherVal->grade_name.'-'.$myteacherVal->section_name.'-('.ucfirst($myteacherVal->name).')';
											
						$mainGroupArr[$key] = new \stdClass(); //the magic see new object member created on the fly without warning.
						$mainGroupArr[$key]->id = $myteacherVal->id;
						$mainGroupArr[$key]->main_group_id = $main_group_id;
						$mainGroupArr[$key]->name = $myteacherVal->name;
						$mainGroupArr[$key]->group_name = $main_group_name;
						$mainGroupArr[$key]->group_image = url('/').'/public/uploads/icon/icon_1644316802.png';
						$mainGroupArr[$key]->school_id = $myteacherVal->memberSchool->school_id;	
						$mainGroupArr[$key]->grade_id =  $myteacherVal->memberGrade->grade_id;
						$mainGroupArr[$key]->section_id = $myteacherVal->memberSection->section_id;	
						
						$groupID =  base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$user_id.'-'.$myteacherVal->id);
						
										
						$last_msg_info = DB::table('chat_msg as c')
										->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording')
										->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
										->where('c.group_id', '=', $groupID)
										->orderBy('c.id', 'DESC')
										->first();
						$myteacher[$key]->main_group_id = '';	
						$myteacher[$key]->school_id = $myteacherVal->school_id;	
						$myteacher[$key]->grade_id =  $myteacherVal->grade_id;
						$myteacher[$key]->section_id = $myteacherVal->section_id;	
						$myteacher[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
						$myteacher[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
						$myteacher[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
						$myteacher[$key]->group_id = $groupID;	
						$myteacher[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
						$myteacher[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
						$myteacher[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
						$myteacher[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
					}
				}
				
				if(!empty($mainGroupArr)){
					foreach($mainGroupArr as $key=>$mainGroupArrval){
						$main_group_id = !empty($mainGroupArrval->main_group_id)? $mainGroupArrval->main_group_id :'';
						$tutor_id = $mainGroupArrval->id;
						$last_msg_info = DB::table('chat_msg as c')
						->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording')
						->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
						->where('c.group_id', '=', $main_group_id)
						->orderBy('c.id', 'DESC')
						->first();
						$mainGroupArr[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
						$mainGroupArr[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
						$mainGroupArr[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
						$mainGroupArr[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
						$mainGroupArr[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
						$mainGroupArr[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
						$mainGroupArr[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
						array_push($myteacher,$mainGroupArrval);
					}
				}
				$teacherData = collect($myteacher)->sortByDesc('chat_id')->values();
				$data['user_id'] =  $user_id;
				$data['userinfo'] =  $userinfo;
				$data['myteacher'] =  $teacherData;
				$returnHTML = view('student/_teacher_list_chat')->with($data)->render();
		}
		return response()->json(['status' => true,'grouptype'=>$grouptype,'returnHTML'=>$returnHTML]);
    }
		
