	public function sendForwardMedia(Request $request){
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		//$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$tutor = $request->input('tutor');
		$active_group_id = $request->input('active_group_id');
		$forward_doc = $request->input('forward_doc');
		$file_type = $request->input('forward_type');
		$forward_media_date = $request->input('forward_media_date');
		$forward_media_time = $request->input('forward_media_time');
		
		$message_date = date('Y-m-d', strtotime($forward_media_date));
		$message_time = date('h:i a',strtotime($forward_media_time));
		
		$message_date_time = date('d-M-Y', strtotime($forward_media_date)).' '.date('h:i a',strtotime($forward_media_time)) ;
		
		$forward_docArr = explode(",",$forward_doc);
		 
		$student_group =  DB::table('member_section')
						  ->join('member_school','member_school.user_id','=','member_section.user_id')
						  ->select('member_school.school_id','section_id','grade_id')->where('member_section.user_id', '=', $user_id)->where('member_section.status',1)->first();
		
		$section_grade = !empty($student_group) ? $student_group->section_id.'_'.$student_group->grade_id : '';
		$parent_group = !empty($student_group) ? base64_encode($student_group->school_id.''.$student_group->grade_id.''.$student_group->section_id): '';
		$allowedImg = array('gif', 'png', 'jpg','jpeg');
		$allowedAudio = array('mp4', 'wav', 'ogg','mp3','webm','wmv');
		$returnHTML = "";
		$totalMessageArr = array();
		$checkFlag = false;	
		
		if(!empty($tutor) && !empty($forward_doc)){
					if (!empty($profile_pic)) {
						$path = parse_url($profile_pic);
						if(isset($path['scheme']) == 'https' || isset($path['scheme']) == 'http'){
							$url = $profile_pic;
						}else{
							$url = url('/') . '/public/uploads/profile_img/'.$profile_pic;	
						}
					}else {
						$url = url('/') . '/resources/assets/images/student_icon.png';
					}
			foreach($forward_docArr as $key_one=>$forward_docArrVal){
				
				$message = $forward_docArrVal;
				$senderArr = array();
				foreach($tutor as $key =>$tutorVal){
				
					$senderArr = array(
						'group_id' => $key,
						'institute_id' => $institute_id ,
						'sender_id' => $user_id ,
						'msg' =>$forward_docArrVal,
						'date' =>$message_date,
						'file_type' =>$file_type,
						'time' =>$forward_media_time,
						'status' => 1,
						'created_at' => date('Y-m-d H:i:s'),
					);
					if($file_type == 1 || $file_type == 3 ){
						$senderArr['is_share_file'] = 1;
						$senderArr['mime_type'] = $mime_type = mime_content_type(public_path().'/uploads/chat_share_file/'.$message);
					}
					
					
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
					if($insert_Id){
							$chatMsgStatus = array(
								'receiver_id' => $tutorVal,
								'chat_msg_id' =>$insert_Id,
