								$listOption = "<a  class='dropdown-button with_frWrd' href='#' data-activates='dropdown".$insert_Id."'><i class='fa fa-angle-down' aria-hidden='true'></i></a><ul id='dropdown".$insert_Id."' class='dropdown-content'><li><a href='#'>'.__('messages.reply').'</a></li><li><a href='javascript:void(0)' onclick='message_forward(".$insert_Id.",1)'>'.__('messages.forward').'</a></li><li><a href='javascript:void(0)' onclick='removeChatMessage(".$insert_Id.")'>'.__('messages.remove').'</a></li></ul>";
								$msgText = "<span class='newfilesharedcls'><a href='javascript:void(0)' style='text-decoration:none;'><img src='".url('resources/assets/images/play_icon.jpg')."' data-url='".url('/public/uploads/chat_share_file').'/'.$message."' data-mime-type='".$mime_type."' class='videoPreviweCls'></a></span>";
