								$msgText = "<span class='newfilesharedcls'><a href='javascript:void(0)' style='text-decoration:none;'><audio controls><source src='".url('/public/uploads/chat_share_file').'/'.$message."' type='".$mime_type."'></audio></a></a></span>";
							}
