							$listOption = "<a class='dropdown-button with_frWrd' href='#' data-activates='dropdown".$insert_Id."'><i class='fa fa-angle-down' aria-hidden='true'></i></a><ul id='dropdown".$insert_Id."' class='dropdown-content'><li><a href='".url('/download').'/'.$insert_Id."'>'.__('messages.download').'</a></li><li><a href='#'>'.__('messages.reply').'</a></li><li><a href='javascript:void(0)' onclick='message_forward(".$insert_Id.",1)'>'.__('messages.forward').'</a></li><li><a href='javascript:void(0)' onclick='removeChatMessage(".$insert_Id.")'>'.__('messages.remove').'</a></li></ul>";
							$msgText = "<span style='color:#00b6bf' class='newfilesharedcls'>New file shared</span><br><a href='" . url('/download') . '/'.$insert_Id. "' style='text-decoration:none;border-radius:5px;background-color:#00b6bf;text-align:center;height:35px;line-height:35px;width:100px;color:white;display:block'>View File</a></span>";
