						  $msgText = '<a href="'.$message.'" target="_blank">'.$message.'</a>';
						}else{
							$listOption = "<a class='dropdown-button with_frWrd' href='#' data-activates='dropdown".$insert_Id."'><i class='fa fa-angle-down' aria-hidden='true'></i></a><ul id='dropdown".$insert_Id."' class='dropdown-content'><li><a href='javascript:void(0)' data-message-id='".$insert_Id."' data-edit-message='".$message."' class='editMessageCls'>Edit</a></li><li><a href='javascript:void(0)' onclick='copyDivToClipboard(".$insert_Id.")'>'.__('messages.copy').'</a></li><li><a href='#'>'.__('messages.reply').'</a></li><li><a href='javascript:void(0)' onclick='message_forward(".$insert_Id.",1)'>'.__('messages.forward').'</a></li><li><a href='javascript:void(0)' onclick='removeChatMessage(".$insert_Id.")'>'.__('messages.remove').'</a></li></ul>";
							$msgText = !empty($message)? $message :'';	
						}
					}
					
				
				$chat_message ='<div class="message" id="chatMessageDiv_'.$insert_Id.'"><img src="'.$url.'">
					<div class="bubble singlemediaCls">'.$listOption.$msgText.'<div class="corner">
					</div><span>'.$message_date_time.'</span></div></div>';
				
				if($active_group_id ==  $key){
					$returnHTML  .='<div class="message right" id="chatMessageDiv_'.$insert_Id.'"><img src="'.$url.'">
									<div class="bubble singlemediaCls">'.$listOption.$msgText.'<div class="corner">
									</div><span>'.$message_date_time.'</span></div></div>';	
				}	
					
				$totalMessage =	Helper::getMessageCount($tutorVal);
				$totalgroupMessage = Helper::getMessageCountByUser($tutorVal,$user_id);
				$totalGradeSectionMessage = Helper::getMessageCountByGroup($parent_group,$tutorVal);
				$msgsend =  array('totalMessage'=>$totalMessage,
								 'totalGradeSectionMessage'=>$totalGradeSectionMessage,
								 'totalgroupMessage'=>$totalgroupMessage,
								 'chat_message'=>$chat_message,
								 'last_message'=>$message,
								 'time'=>$message_time,
								 'student_id'=>$user_id,
								 'section_grade'=>$section_grade,
								 'gid'=>$active_group_id,
								 'chatboxmsgid'=>base64_decode($active_group_id),
								 'chat_id'=>$insert_Id,
								 'user_id'=>$tutorVal);                              
				event(new ChatMessage($msgsend));		
				}
		    }
		}
		if($file_type==1){
		  $message = 'file share successfully';
		}elseif($file_type==2){
		  $message = 'link share successfully';	
		}elseif($file_type==3){
			$message = 'document share successfully';
		}
		if($checkFlag){
		 return response()->json(['status' => true,'returnHTML'=>$returnHTML,'message'=>$message]);	
		}else{
		return response()->json(['status' => true,'returnHTML'=>$returnHTML,'message'=>'Please try again']);	
		}
		
	}
	
