	public function getmessageCounter() {
        $user_id = Auth::user()->id;
        $totalmessage = DB::table('chat_msg_status')
                ->where('receiver_id', '=', $user_id)
                ->where('chat_msg_status.is_read', '=', 0)
                ->where('chat_msg_status.status', '=', 0)
                ->count();
        return response()->json(['status' => true, 'totalmessage' => $totalmessage,]);
    }
		
	public function removeChatMessage(Request $request){
		
		$user_id = Auth::user()->id;
		$tutor_id = $request->tutor_id;
		$active_group_id = $request->active_group_id;
		$group_id = $request->group_id;
		$groupchat_id = $request->groupchat_id;
		$gradesection_group_id = $request->gradesection_group_id;
		$b2c_group_id = $request->b2c_group_id;
		$chat_id = $request->chat_id;
		$share_file_id = $request->share_file_id;
		$recevier_id = $request->recevier_id;
	
