	public function getSearchTeacher(Request $request){
		
	    $serach_txt = $request->serach_txt;
        $user_id = Auth::user()->id;
		$userinfo = DB::table('users')
					->Join('member_school', 'member_school.user_id', '=', 'users.id')
					->Join('member_section', 'member_section.user_id', '=', 'member_school.user_id')
					->select('users.id','member_school.school_id','member_section.grade_id','member_section.section_id')
					->where('users.id', '=', $user_id)
					->where('users.role_id', '=', 3)
					->where('member_section.status', '=', 1)
					->first();
							
		$myteacher = DB::table('users')
			->select('users.id','users.fullname as name','users.profile_pic','users.is_login' ,'users.status','member_school.school_id','member_grade.grade_id','member_grade.grade_name','member_section.section_id','member_section.section_name')
			->Join('member_school', 'member_school.user_id', '=', 'users.id')
			->join('member_grade', 'member_grade.user_id', '=', 'users.id')
			->Join('member_section', 'member_section.user_id', '=', 'users.id')
			->where('member_school.school_id', '=', $userinfo->school_id)
			->Where('member_grade.grade_id', '=', $userinfo->grade_id)
			->Where('member_section.section_id', '=', $userinfo->section_id)
			->where('users.role_id', '=', 2)
			->where('users.status', '=', 1)
			->where(function ($query) use ($serach_txt) {
				if(!empty($serach_txt)){
					$query->orWhere('users.fullname', 'like', '%' . $serach_txt . '%');
				} 
			})
			->groupBy('users.id')
			->orderBy('users.fullname', 'ASC')
			->get()->all();
			$data['user_id'] = $user_id;
			$data['myteacher'] = $myteacher;
			$returnHTML = view('student/_search_teacher_forward_model')->with($data)->render();
			return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
	}
	
	public function getMessageForwardTutorListPage(Request $request){
		
		$user = Auth::user();
        $user_id = $user->id;
        $institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
				
		$request_type =  $request->type; 
	    $search_txt =  $request->search_txt; 
		$grouptype = $request->grouptype;
		$returnHTML="";
		if($grouptype=='groups'){
			$chatGroup = DB::table('chat_group')
					->join('chat_group_member', 'chat_group_member.group_id', '=', 'chat_group.id')
					->select('chat_group.id','chat_group.group_id', 'chat_group.group_name', 'chat_group.group_image')
					->where('chat_group_member.user_id', $user_id)
					->where('chat_group.status', 1)
					->where('chat_group.institute_id', $institute_id)
					->where(function ($query) use ($search_txt) {
						$query->orWhere('group_name', 'like', '%' . $search_txt . '%');
					})
					->get();
		if(!empty($chatGroup)){
			foreach($chatGroup as $key=>$chat_groupVal){
				$last_msg_info = DB::table('chat_msg as c')
					->select('c.id as chat_id', 'c.group_id', 'c.sender_id','c.created_at', 'c.msg','c.is_share_file','c.is_link')
					->where('c.group_id', '=', $chat_groupVal->group_id)
					->orderBy('created_at', 'DESC')
					->first();
					$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
					$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
			}
		}					
		$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();						
		$data['student_id'] = $user_id;
		$data['chat_group'] = $chat_group;
		$returnHTML = view('student/_group_list')->with($data)->render();
		}
		elseif($grouptype=='b2c'){
			
		}
		else{
			//echo 1;die;
		
		 $userinfo = DB::table('users')
					->where([
						['users.institute_id', '=', $institute_id],
						['users.id', '=', $user_id],
						['users.role_id', '=', 3],
						['users.status', '=', 1],
					])
					->select('users.id','users.fullname', 'member_school.school_id', 'member_section.grade_id', 'member_section.section_id')
					->join('member_school', function ($join) use ($academic_session_id, $semester_id, $tutorGradeSectionVal) {
						$join->on('member_school.user_id', '=', 'users.id')
							->where('member_school.academic_session_id', '=', $academic_session_id)
							->where('member_school.semester_id', '=', $semester_id)
							->where('member_school.status', '=', 1);
					})
					->join('member_section', function ($join) use ($academic_session_id, $semester_id, $tutorGradeSectionVal) {
						$join->on('member_section.user_id', '=', 'users.id')
							->where('member_section.academic_session_id', '=', $academic_session_id)
							->where('member_section.semester_id', '=', $semester_id)
							->where('member_section.status', '=', 1);
					})
					//->Join('member_school', 'member_school.user_id', '=', 'users.id')
					//->Join('member_section', 'member_section.user_id', '=', 'users.id')
					->first();					
						
					$myteacher = DB::table('users')
						->select('users.id', 'users.fullname as name', 'users.profile_pic', 'users.is_login', 'grades.school_id','member_section.grade_id','grades.grade as grade_name','member_section.section_id','section_name')
						->join('member_section', function ($join) use ($userinfo,$academic_session_id,$semester_id){
							$join->on('member_section.user_id', '=', 'users.id')
								->where('member_section.status', '=', 1)
								->where('member_section.academic_session_id', $academic_session_id)
								->where('member_section.semester_id', $semester_id)
								->where('member_section.section_id', '=', $userinfo->section_id);
						})
						->join('member_grade', function ($join) use ($userinfo,$academic_session_id,$semester_id) {
							$join->on('member_grade.user_id', '=', 'users.id')
								->where('member_grade.academic_session_id', $academic_session_id)
								->where('member_grade.semester_id', $semester_id)
								->where('member_grade.status', '=', 1)
								->where('member_grade.grade_id', '=', $userinfo->grade_id);
						})
						->join('grades', function ($join) use ($userinfo) {
							$join->on('grades.id', '=', 'member_grade.grade_id')
								->where('grades.school_id', '=', $userinfo->school_id);
						})
						->where('users.role_id', '=',2)
						->where('users.institute_id', '=', $institute_id)
						->where(function ($query) use ($search_txt) {
							$query->orWhere('users.fullname', 'like', '%' . $search_txt . '%');
							$query->orWhere('grade_name', 'like', '%' . $search_txt . '%');
							$query->orWhere('section_name', 'like', '%' . $search_txt . '%');
						})
						->groupBy('users.id')
						->orderBy('users.first_name', 'ASC')
						->get()
						->all(); 
								
					//print_r($myteacher);
					//die;			
					$mainGroupArr =array(); 
						
					if(!empty($myteacher)){
						foreach($myteacher as $key=>$myteacherVal){
							$main_group_id = base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$myteacherVal->id);
							$groupID =  base64_encode($myteacherVal->school_id.'-'.$myteacherVal->grade_id.'-'.$myteacherVal->section_id.'-'.$user_id.'-'.$myteacherVal->id);
							
							$last_msg_info = DB::table('chat_msg as c')
										->select('c.id as chat_id')
										->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
										->where('c.group_id', '=', $main_group_id)
										->orderBy('created_at', 'DESC')
										->first();
							
							$mainGroupArr[$key] = new \stdClass(); //the magic see new object member created on the fly without warning.
							$mainGroupArr[$key]->id = $myteacherVal->id;
							$mainGroupArr[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id:'';
							$mainGroupArr[$key]->main_group_id = $main_group_id;
							$mainGroupArr[$key]->name = $myteacherVal->name;
							$mainGroupArr[$key]->group_name = $myteacherVal->grade_name.'-'.$myteacherVal->section_name.'-('.ucfirst($myteacherVal->name).')';;
							$mainGroupArr[$key]->group_image = url('/').'/public/uploads/icon/icon_1644316802.png';
							$mainGroupArr[$key]->school_id = $myteacherVal->school_id;	
							$mainGroupArr[$key]->grade_id =  $myteacherVal->grade_id;
							$mainGroupArr[$key]->section_id = $myteacherVal->section_id;	
							
							$lastMsgInfo = DB::table('chat_msg as c')
										->select('c.id as chat_id')
										->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
										->where('c.group_id', '=', $groupID)
										->orderBy('created_at', 'DESC')
										->first();
							$myteacher[$key]->main_group_id = '';	
							$myteacher[$key]->school_id = $myteacherVal->school_id;	
							$myteacher[$key]->grade_id =  $myteacherVal->grade_id;
							$myteacher[$key]->section_id = $myteacherVal->section_id;	
							$myteacher[$key]->group_id = $groupID;	
							$myteacher[$key]->chat_id = !empty($lastMsgInfo->chat_id) ? $lastMsgInfo->chat_id:'';;	
						}
					}
					
					if(!empty($mainGroupArr)){
						foreach($mainGroupArr as $key=>$mainGroupArrval){
							$main_group_id = !empty($mainGroupArrval->main_group_id)? $mainGroupArrval->main_group_id :'';
							array_push($myteacher,$mainGroupArrval);
						}
					}
					
					$teacherData = collect($myteacher)->sortByDesc('chat_id')->values();
					$data['user_id'] =  $user_id;
					$data['userinfo'] =  $userinfo;
					$data['myteacher'] =  $teacherData;
					$returnHTML = view('student/_message_forward_teacher_list_page')->with($data)->render();
					
		}
		/* if($request_type == 'chatmessage_forward'){
			
		}else{
			$returnHTML = view('student/_shared_material_forward_teacher_list_page')->with($data)->render();	
		}  */
		return response()->json(['status' => true,'grouptype'=>$grouptype,'returnHTML'=>$returnHTML]);
	    die;
	}
		
