	/*start create groups chat section*/  
	
	public function getCreatedGroup(Request $request){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		
		$chatGroup = DB::table('chat_group')
						->join('chat_group_member', function ($join) use($user_id) {
							$join->on('chat_group_member.group_id', '=', 'chat_group.id')
								->where('chat_group_member.user_id', '=', $user_id);
						})
						->select('chat_group.id', 'chat_group.group_name', 'chat_group.group_image', 'chat_group.group_id', DB::raw('(SELECT COUNT(*) FROM chat_msg JOIN chat_msg_status ON chat_msg_status.chat_msg_id = chat_msg.id WHERE chat_msg.group_id = chat_group.group_id AND chat_msg_status.receiver_id = "' . $user_id . '" AND chat_msg_status.is_read = 0 AND chat_msg_status.status = 0) AS unread_count'))
						->where(['chat_group.institute_id'=>$institute_id, 'chat_group.status'=>1])
						->get()
						->all();
						if (!empty($chatGroup)) {
							foreach ($chatGroup as $key => $chat_groupVal) {
								$last_msg_info = DB::table('chat_msg as c')
									->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file', 'c.is_link', 'chat_shared_file.file_type', 'chat_shared_file.file_name', 'chat_shared_file.file_mime_type', 'chat_shared_file.is_recording')
									->leftJoin('chat_shared_file', 'chat_shared_file.chat_id', '=', 'c.id')
									->where('c.group_id', '=', $chat_groupVal->group_id)
									->orderBy('created_at', 'DESC')
									->first();
								$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';
								$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';
								$chatGroup[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
								$chatGroup[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';
								$chatGroup[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';
								$chatGroup[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';
								$chatGroup[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
								$chatGroup[$key]->unread_count = $chat_groupVal->unread_count;
							}
						}
					$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();						
					$data['student_id'] = $user_id;
					$data['chat_group'] = $chat_group;
					$returnHTML = view('student/_chat_group_list')->with($data)->render();
					return response()->json(['status' => true,'returnHTML'=>$returnHTML]);					
	}
		
