                ->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"),'c.is_share_file', 'c.is_link','c.is_meet_in_classroom','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.is_forward','c.track_duration','users.id','users.role_id','users.profile_pic','users.fullname as sender_name')
