	//b2c chat function start from here
	public function save_message_b2c(Request $request){
		
		
		$user = Auth::user();
		$user_id = $user->id;
		$studentName = $user->fullname;
		$institute_id = $user->institute_id;
		$recevier_id = $request->input('recevier_id');
		$msg_date  = $request->msg_date;
		$msg_time = $request->input('msg_time');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$msg_date_time = $msg_date.' '.$msg_time;
	
		$message = trim($request->input('message'));
		$active_group_id =  base64_encode($recevier_id.'-'.$user_id.'-'.$institute_id);
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',trim($currentDateTime), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
		$utcDate = Carbon::createFromFormat('d-m-Y h:i a',trim($msg_date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d');
		$utcTime = Carbon::createFromFormat('d-m-Y h:i a',trim($msg_date_time), $userTimeZone)->setTimezone('UTC')->format('H:i:s');
		
		if(!empty($recevier_id)){
			
			$senderArr = array(
							'group_id' =>$active_group_id,
							'institute_id' => $institute_id ,
							'academic_session_id' => $academic_session_id,
							'semester_id' => $semester_id,
							'sender_id' => $user_id ,
							'msg' => $message,
							'status' => 1,
							'created_at' => $utcCurrentDateTime,
						);
			if (!chatGroup::where(['group_id'=>$active_group_id,'institute_id'=>$institute_id])->exists()) {
				$userData = DB::table('users')->select('fullname')->where(['id'=>$recevier_id,'institute_id'=>$institute_id])->first();
				$teacherName = !empty($userData->fullname)? $userData->fullname : '';
				$group_name = $teacherName.'-'.$studentName;
				DB::table('chat_group')->insert(['group_id' =>$active_group_id,
												'institute_id' => $institute_id,
												'group_name' =>$group_name,
												'chat_type' =>1,
												'status' =>1,
												'tutor_id' =>$recevier_id,
												'student_id' =>$user_id,
												'created_at' => $utcCurrentDateTime,
												]);
			}
			
			$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
			if($insert_Id){
				$chatMsgStatus[] = array(
					'receiver_id' => $recevier_id,
					'chat_msg_id' =>$insert_Id,
					'is_read' => 0,
					'status' => 0,
					'created_at' => $utcCurrentDateTime,
				);
				DB::table('chat_msg_status')->insert($chatMsgStatus);
			}
			$last_msg_info = DB::table('chat_msg as c')
							->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"),'c.is_share_file', 'c.is_link', 'c.file_type', 'c.is_reply', 'c.reply_message_id', 'users.id', 'users.profile_pic', 'users.fullname as sender_name')
							->join('users', 'users.id', '=', 'c.sender_id')
							->where('c.group_id', $active_group_id)
							->where('c.sender_id', $user_id)
							->orderBy('c.id', 'DESC')
							->first();
				if (!empty($last_msg_info->profile_pic)) {
					$path = parse_url($last_msg_info->profile_pic);
					if(isset($path['scheme']) == 'https' || isset($path['scheme']) == 'http'){
						$url = $last_msg_info->profile_pic;
					}else{
						$url = url('/') . '/public/uploads/profile_img/'.$last_msg_info->profile_pic;	
					}
				} else {
					$url = url('/') . '/resources/assets/images/student_icon.png';
				}
				$last_message = !empty($last_msg_info->msg)? $last_msg_info->msg :'';	
				$message_date_time = Helper::getDatetime($last_msg_info->date_time);
				$message_time = Helper::getTime($last_msg_info->date_time);
				$message_reply = "'".$message."'";
				$chat_shared_file_id ="''";
				$message ='<div class="message right"><img src="'.$url.'"><div class="bubble">'.$last_message.'<div class="corner"></div><span>'.$message_time.'</span></div></div>';
				$totalMessage =	Helper::getMessageCount($recevier_id);
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'gid'=>$active_group_id,
								  'student_id'=>$user_id,
								  'user_id'=>$recevier_id,
								  'update_message_id'=>'',
								  'remove_message_id'=>'',
								  'remove_bulk_message_id'=>'',
								  'message_type'=>'b2c'
								);                              
				event(new ChatMessage($msgsend));	
				return response()->json(['status' => true,'message' =>$message]);	
		}				
	}
	
	public function getUserListB2C(Request $request){
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$data['user_id'] = $user_id;
		$data['userTimeZone'] = $userTimeZone; 
		
		$data['active_group_id'] = $request->active_group_id;
		$data['groups'] =  DB::table('chat_group')
							->select('users.id', 'users.fullname', 'users.profile_pic', 'users.is_login', 'chat_group.group_id', 'last_msg.msg', 'chat_shared_file.file_type', 'chat_shared_file.file_name', 'chat_shared_file.file_mime_type', 'chat_shared_file.is_recording', 'last_msg.created_at')
							->join('users', 'chat_group.tutor_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->where('last_msg.id', '=', DB::raw('(SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)'));
							})
							->leftJoin('chat_shared_file', function ($join) {
								$join->on('chat_shared_file.chat_id', '=', 'last_msg.id')
									 ->whereExists(function ($query) {
										$query->select(DB::raw(1))
											  ->from('chat_shared_file')
											  ->whereRaw('chat_shared_file.chat_id = last_msg.id')
											  ->orderByDesc('chat_shared_file.id')
											  ->limit(1);
									});
							})
							->where('chat_group.student_id', $user_id)
							->groupBy('chat_group.group_id')
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();

		$returnHTML = view('student/_b2c_user_list')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
	
	public function getConverstionB2C(Request $request){
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$tutor_id = $request->get('tutor_id'); 
		$active_group_id =  base64_encode($tutor_id.'-'.$user_id.'-'.$institute_id);
		$chatRecords = DB::table('chat_msg as c')
						->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'), '%d-%m-%Y %h:%i %p') as date_time"),'c.is_share_file', 'c.is_link','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.is_forward','c.track_duration','users.id','users.profile_pic','users.fullname as sender_name')
						->join('users', 'users.id', '=', 'c.sender_id')
						->where('c.group_id', '=', $active_group_id)
						->where('c.institute_id', '=', $institute_id)
						->orderBy('c.created_at', 'ASC')
						->get();
					$chatRecordsByDay = $chatRecords->groupBy(function($record) {
						return date('Y-m-d', strtotime($record->date_time));
					});
		$data['user_id'] = $user_id;			
		$data['chatRecords'] = $chatRecords;			
		$data['chatRecordsByDay'] = $chatRecordsByDay;			
		$returnHTML = view('student/_b2c_chat_message')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;				
		
	}
	
	public function getB2CUserListPage(Request $request){
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$search_txt = $request->search_txt;
		$data['user_id'] = $user_id; 
		$data['active_group_id'] = $request->active_group_id;
		$data['groups'] = DB::table('chat_group')
							->select('users.id','users.fullname', 'users.profile_pic','users.is_login','chat_group.group_id', 'last_msg.msg', DB::raw("DATE_FORMAT(CONVERT_TZ(last_msg.created_at, 'UTC', '{$userTimeZone}'), '%d-%m-%Y %h:%i %p') as date_time"))
							->join('users', 'chat_group.tutor_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->whereRaw('last_msg.id = (SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)');
							})
							->where('chat_group.student_id', $user_id)
							->where(function ($query) use ($search_txt) {
								if(!empty($search_txt)){
									$query->orWhere('users.fullname', 'like', '%' . $search_txt . '%');
									$query->orWhere('users.first_name', 'like', '%' . $search_txt . '%');
								} 
							})
							->orderBy('users.first_name', 'ASC')
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();
		$returnHTML = view('student/_message_forward_b2c_user_list_page')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
	
