	public function getLastChatConversion(Request $request){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		
        $update_message_id = $request->get('update_message_id');
        $active_group_id = $request->get('active_group_id');
	    $group_type = $request->get('group_type');
		
     	$data['lastMessageInfo'] =  DB::table('chat_msg as c')
							->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"),'c.is_share_file', 'c.is_link','c.is_meet_in_classroom','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.is_forward','c.track_duration','c.is_name_header','users.id','users.role_id','users.profile_pic','users.fullname as sender_name')
							->Join('users', 'users.id', '=', 'c.sender_id')
							->where('c.group_id', '=', $active_group_id)
							->where('c.institute_id', '=', $institute_id)
							->where('c.academic_session_id', '=', $academic_session_id)
							->where('c.semester_id', '=', $semester_id)
							->orderBy('chat_id', 'DESC')
							->first();
		$returnHTML = view('student/_last_chat_conversion')->with($data)->render();
        return response()->json(['status' => true,'chat_id'=>$chat_id,'update_message_id'=>$update_message_id,'chatboxmsgid'=>base64_decode($active_group_id),'chat_message' => $returnHTML]);
        die;
		
	}
		
