	public function widgetShareFileMedia(Request $request) {
			$user = Auth::user();
			$user_id = $user->id;
			$institute_id = $user->institute_id;
			$academic_session_id = Session::get('aSessionId');
			$semester_id = Session::get('semesterId');

			$now = Carbon::now();
			$userTimeZone = $now->timezone->getName();

			$active_group_id = $request->input('active_group_id');
			$message = trim($request->input('txt_message'));
			$receiver_id = $request->input('receiver_id');
			$group_type = $request->input('group_type');
			$randomIdArr = explode(",",$request->input('random_id'));

			$msg_date_time = date('d-m-Y h:i a', strtotime($request->input('date_time')));
			$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
			$utcCurrentDateTime = Carbon::createFromFormat('d-m-Y h:i a', trim($msg_date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');

			$singleImgCls = "";
			$dataArr = array();
			if ($request->hasfile('file')) {
				foreach($request->file('file') as $file) {
					$file_name = $file->getClientOriginalName();
					$file_mime_type = $file->getClientMimeType();
					$upload_path = public_path().'/uploads/chat_share_file/';
					if (!file_exists($upload_path)) {
						mkdir($upload_path, 0777, true);
					}
					$file->move($upload_path, $file_name);
					$videotoimg="";
					if(strstr($file_mime_type, "video/")){
						$videotoimg = Helper::videotoImg($file_name);
					}
					$dataArr[] = array('file_name'=>$file_name,
										'file_mime_type'=>$file_mime_type,
										'file_type'=>2,
										'other_file'=>$videotoimg,
										'created_date'=>$utcCurrentDateTime);
				}
			}

			$senderArr = array(
				'sender_id' => $user_id,
				'institute_id' => $institute_id,
				'academic_session_id' => $academic_session_id,
				'semester_id' => $semester_id,
				'msg' => $message,
				'is_share_file' => 1,
				'file_type' =>2,
				'status' => 1,
				'created_at' => $utcCurrentDateTime,
			);

			$insert_Id = "";
			$section_grade = "";
			$school_grade_section = "";
				
		if($group_type =='gradesection'){
			
			$gradeSectionGropId = base64_decode($active_group_id);
			$gradeSectionArr = explode("-",$gradeSectionGropId);
			$teacher_id = $gradeSectionArr[3];
			$section_grade = !empty($gradeSectionArr[2])? $gradeSectionArr[2].'_'.$gradeSectionArr[1] :'';
			$school_grade_section = !empty($gradeSectionArr[2]) ? $gradeSectionArr[0].'_'.$gradeSectionArr[1].'_'.$gradeSectionArr[2] :'';
						
			$groupMember = DB::table('member_section')
							->join('member_school', function ($join) use ($gradeSectionArr) {
								$join->on('member_school.user_id', '=', 'member_section.user_id')
									->where('member_school.status', '=', 1)
									->where('member_school.school_id', '=', $gradeSectionArr[0]);
							})
							->join('member_grade', function ($join) {
								$join->on('member_grade.user_id', '=', 'member_section.user_id')
									->where('member_grade.status', '=', 1);
							})
							->join('users', function ($join) use ($institute_id) {
								$join->on('member_school.user_id', '=', 'users.id')
									->where('users.role_id', '=', 3)
									->where('users.institute_id', '=', $institute_id);
							})
							->where([
								['member_section.grade_id', '=', $gradeSectionArr[1]],
								['member_section.section_id', '=', $gradeSectionArr[2]],
								['member_section.status', '=', 1],
								['member_school.status', '=', 1],
								['member_section.user_id', '!=', $user_id],
							])
							->pluck('member_section.user_id')
							->toArray();
				
			if(!empty($receiver_id)){
				$senderArr['group_id'] = $active_group_id;
				$senderArr['is_name_header'] = 1;
							
				$chatMsgStatus = array();		
				$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
				if($insert_Id){
					foreach($groupMember as $key=>$recevierIdArrVal){
						if($insert_Id){
							$chatMsgStatus[] = array(
								'receiver_id' => $recevierIdArrVal,
								'chat_msg_id' =>$insert_Id,
								'is_read' => 0,
								'status' => 0,
								'chat_msg_type' => 1,
								'created_at' => $utcCurrentDateTime,
							);
						}
					}
					DB::table('chat_msg_status')->insert($chatMsgStatus);
					if(!empty($dataArr)){
						foreach($dataArr as $key => $csm){
						  $dataArr[$key]['chat_id'] = $insert_Id;
						}
					 DB::table('chat_shared_file')->insert($dataArr);	
					}
				}
			}
		}
		
		else if($group_type =='group'){
			
				$groupMember = DB::table('chat_group_member')
								->select('user_id','group_id')
								->where('chat_group_member.group_code', '=', $active_group_id)
								->where('chat_group_member.user_id', '!=' ,$user_id)
								->get()
								->all();
								
				$senderArr['group_id'] = $active_group_id;
				$senderArr['is_name_header'] = 1;				
										
				$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
				$chatMsgStatus= array();
				if($insert_Id){
					foreach($groupMember as $key=>$group_memberVal){
						$chatMsgStatus[] = array(
											'receiver_id' =>$group_memberVal->user_id,
											'chat_msg_id' =>$insert_Id,
											'is_read' => 0,
											'status' => 0,
											'chat_msg_type' => 2,
											'created_at' => $utcCurrentDateTime,
										);
					}
					DB::table('chat_msg_status')->insert($chatMsgStatus);
					if(!empty($dataArr)){
						foreach($dataArr as $key => $csm){
						  $dataArr[$key]['chat_id'] = $insert_Id;
						}
					 DB::table('chat_shared_file')->insert($dataArr);	
					}
				}
		}
		
		else if($group_type =='b2c'){
			
			$groupArr = explode("-",$receiver_id);
			$tutor_id =!empty($groupArr[0])? $groupArr[0] :'' ;
			
			$senderArr['group_id'] = $active_group_id;
			$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
			if($insert_Id){
					$chatMsgStatus = array(
						'receiver_id' => $tutor_id,
						'chat_msg_id' =>$insert_Id,
						'is_read' => 0,
						'status' => 0,
						'chat_msg_type' => 3,
						'created_at' => $utcCurrentDateTime,
					);
			   DB::table('chat_msg_status')->insert($chatMsgStatus);
			   if(!empty($dataArr)){
					foreach($dataArr as $key => $csm){
					  $dataArr[$key]['chat_id'] = $insert_Id;
					}
				 DB::table('chat_shared_file')->insert($dataArr);	
				}
			}
		}
		
		else{
			
			$student_group =  DB::table('member_section')
							  ->join('member_school','member_school.user_id','=','member_section.user_id')
							  ->select('member_section.school_id','section_id','grade_id')
							  ->where('member_section.user_id', '=', $user_id)
							  ->where('member_school.status',1)
							  ->where('member_section.status',1)
							  ->first();
	
				$section_grade = !empty($student_group) ? $student_group->section_id.'_'.$student_group->grade_id : '';
				$parent_group = !empty($student_group) ? base64_encode($student_group->school_id.''.$student_group->grade_id.''.$student_group->section_id): '';
			
				if(!empty($receiver_id)){
					
					$senderArr['group_id'] = $active_group_id;
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
					
					if($insert_Id){
					   DB::table('chat_msg_status')->insert(array('receiver_id' => $receiver_id,
																   'chat_msg_id' =>$insert_Id,
																   'is_read' => 0,
																   'status' => 0,
																   'chat_msg_type' =>1,
																   'created_at' => $utcCurrentDateTime));
					   if(!empty($dataArr)){
							foreach($dataArr as $key => $csm){
							  $dataArr[$key]['chat_id'] = $insert_Id;
							}
						 DB::table('chat_shared_file')->insert($dataArr);	
						}
					}
				}
		}
		
		$last_msg_info = DB::table('chat_msg as c')
						->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"), 'c.is_share_file', 'c.is_link','c.file_type','c.reply_message_id','users.id','users.profile_pic','users.fullname as sender_name')
						->join('users', 'users.id', '=', 'c.sender_id')
						->where('c.group_id', '=', $active_group_id)
						->where('c.sender_id', '=', $user_id)
						->where('c.institute_id', '=', $institute_id)
						->where('c.academic_session_id', '=', $academic_session_id)
						->where('c.semester_id', '=', $semester_id)
						->orderBy('chat_id', 'DESC')
						->first();
						
				$date_time = Helper::getDatetime($last_msg_info->date_time);
				$chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id :'' ;
