	public function loadMoreMessagesWidget(Request $request){
		$user = Auth::user();
        $user_id = $user->id;
        $institute_id = $user->institute_id;
		
        //$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		
        $academic_session_id = Session::get('aSessionId');
        $semester_id = Session::get('semesterId');
        $active_group_id = trim($request->get('active_group_id'));
        $offset = trim($request->get('offset'));

        $messages = DB::table('chat_msg as c')
            ->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"), 'c.is_share_file', 'c.is_link', 'c.is_meet_in_classroom', 'c.file_type', 'c.mime_type', 'c.is_reply', 'c.reply_message_id', 'c.reply_share_message_id', 'c.is_forward', 'c.track_duration', 'c.is_name_header', 'users.id', 'users.profile_pic', 'users.fullname as sender_name')
            ->join('users', 'users.id', '=', 'c.sender_id')
            ->where('c.group_id', '=', $active_group_id)
            ->where('c.institute_id', '=', $institute_id)
            ->where('c.academic_session_id', '=', $academic_session_id)
            ->where('c.semester_id', '=', $semester_id)
            ->orderBy('chat_id', 'DESC')
            ->offset($offset)
            ->limit(10)
            ->get()
            ->reverse();
	    if ($messages->isNotEmpty()) {
            $data['conversion'] = $messages;
            $returnHTML = view('student/load_more_messages_widget')->with($data)->render();
            return response()->json(['status' => true, 'str_chatbox' => $returnHTML, 'chatboxmsgid' => base64_decode($active_group_id)]);
        } else {
            return response()->json(['status' => false, 'str_chatbox' => 'No more data available', 'chatboxmsgid' => base64_decode($active_group_id)]);
        }
	}
			
	public function removeChatWidgetMessage(Request $request){
		
		
		$user_id = Auth::user()->id;
		$active_group_id = base64_encode($request->active_group_id);
		$chat_id = $request->chat_id;
		$share_file_id = $request->share_file_id;
		$group_type = $request->group_type;
		$res ="";
		$remove_message_id="";
	
		$messagerReceiverId =  DB::table('chat_msg_status')
								->select(DB::raw("GROUP_CONCAT(chat_msg_status.receiver_id) as receiver_id"))
								->join('chat_msg','chat_msg_status.chat_msg_id','=','chat_msg.id')
								//->where('chat_msg.group_id', '=',$active_group_id)
								->where('chat_msg.id', '=',$chat_id)
								->groupBy('chat_msg.group_id')
								->first();
		
		if(!empty($share_file_id)){
			$remove_message_id= "";
			$res =  DB::table('chat_msg')->where('id', '=',$chat_id)->delete();
			if($res){
				DB::table('chat_shared_file')->where(['id'=>$share_file_id,'chat_id'=>$chat_id])->delete();
			}
			$remove_message_id= $chat_id.'_'.$share_file_id;
		}else{
			$res =  DB::table('chat_msg')->where('id', '=',$chat_id)->delete();
			if($res){
				$remove_message_id = $chat_id;
				$result = DB::table('chat_shared_file')->where(['chat_id'=>$chat_id])->first();
				if($result){
					DB::table('chat_shared_file')->where(['chat_id'=>$chat_id])->delete();
				}	
				
			}
		}
		
		if(!empty($res)){
			$totalMessage = array();
			$msgsend = "";
			if($group_type == 'gradesection'){
				$memberArr = explode(",",$messagerReceiverId->receiver_id);
				foreach($memberArr as $key=>$memberID){
				
					$total_message = Helper::getMessageCount($memberID); 
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'user_id'=>$memberID
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'user_id'=>$user_id,
								  'gradesection_id'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'gradesectionchat'); 
			} 
			elseif($group_type == 'group'){
				$memberArr = explode(",",$messagerReceiverId->receiver_id);
				foreach($memberArr as $key=>$memberID){
				
					$total_message = Helper::getMessageCount($memberID); 
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'user_id'=>$memberID
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'user_id'=>$user_id,
								  'cgroupcode'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'groupschat'); 
				
			}
			elseif($group_type == 'b2c'){
				$total_message = Helper::getMessageCount($messagerReceiverId->receiver_id); 
				$msgsend =  array('totalMessage'=>$total_message,
								  'sender_id'=>$user_id,
								  'tutor_id'=>$messagerReceiverId->receiver_id,
								  'group_id'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'b2c'); 
			}
			else{
				
			$total_message = Helper::getMessageCount($messagerReceiverId->receiver_id); 
			$msgsend =  array('totalMessage'=>$total_message,
							  'sender_id'=>$user_id,
							  'user_id'=>$messagerReceiverId->receiver_id,
							  'group_id'=>$active_group_id,
							  'chatboxmsgid'=>base64_decode($active_group_id),
							  'gid'=>$active_group_id,
							  'update_message_id'=>'',
							  'removeMsgId'=>$remove_message_id,
							  'removeBulkMsgId'=>'',
							  'message_type'=>''); 
			}
			 
			event(new ChatMessage($msgsend));
			return response()->json(['status' => true,'chat_id' =>$remove_message_id,'message'=>'message deleted succesfullly']);
		}else{
		   return response()->json(['status' => false,'message'=>'message not delete']);
		}
	}
		
	public function getMessageCounterByUserId(Request $request){
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		
		 $totalMessageCounter =  DB::table('chat_msg_status')
								->where('receiver_id', $user_id)
								->where('chat_msg_status.is_read', 0)
								->selectRaw('SUM(CASE WHEN chat_msg_type = 1 THEN 1 ELSE 0 END) AS count_type_1, SUM(CASE WHEN chat_msg_type = 2 THEN 1 ELSE 0 END) AS count_type_2, SUM(CASE WHEN chat_msg_type = 3 THEN 1 ELSE 0 END) AS count_type_3')
								->first();
		
		//$totalMessageCounter = Helper::getGradeGroupB2cMessageCount($user_id); 
		$totalGradeSectionMessageCount= !empty($totalMessageCounter->count_type_1)? $totalMessageCounter->count_type_1 : 0;
		$totalGroupMessageCount= !empty($totalMessageCounter->count_type_2)? $totalMessageCounter->count_type_2 : 0;
		$totalB2CMessageCount= !empty($totalMessageCounter->count_type_3)? $totalMessageCounter->count_type_3 : 0;
		$totalMessageCount = ($totalGradeSectionMessageCount+$totalGroupMessageCount+$totalB2CMessageCount);
		return response()->json(['status' => true,
								'totalGradeSectionMessageCount' =>$totalGradeSectionMessageCount,
								'totalGroupMessageCount' =>$totalGroupMessageCount,
								'totalB2CMessageCount' =>$totalB2CMessageCount,
								'totalMessageCount' =>$totalMessageCount,
								]);
		
	}
	


	
